import{_ as e,o,c as t,a as n}from"./app.aeaf9fcc.js";const m=JSON.parse('{"title":"Wee786Harry v. Wingzero54, Jun 2018","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/wee786harry_v_wingzero54_jun_2018.md","lastUpdated":1666477380000}'),r={name:"government/court-cases-precedents/wee786harry_v_wingzero54_jun_2018.md"},a=n('<h1 id="wee786harry-v-wingzero54-jun-2018" tabindex="-1">Wee786Harry v. Wingzero54, Jun 2018 <a class="header-anchor" href="#wee786harry-v-wingzero54-jun-2018" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With meat312 presiding, on 7th June 2018, Wee786Harry charged Wingzero54 with Assault. Wingzero54 was found guilty of Assault and ordered to pay 1 iron in restitution.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>meat312</strong>:</p><blockquote><p>I am available. Wee786Harry Please begin with your opening statements</p></blockquote><p><strong>Wee786Harry</strong>:</p><blockquote><p>I am suing Wingzero54 as I was minding my business and wingzero (a judge who punished me for hitting others previously) hit me with his god sword and took me to half a hearts.</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/348687557455904778/454107406083817503/Screen_Shot_2018-06-07_at_01.15.20.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/348687557455904778/454107406083817503/Screen_Shot_2018-06-07_at_01.15.20.png</a></p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>Wingzero54 Opening statements</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>Wee Harry was making threatening statements to Orin and I felt it necessary to strike him</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>Evidence of this? or perhaps Orinnari whitnessed?</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>I also felt Harry deserved a taste of his own medicine, considering he has been running around smacking people</p></blockquote><p><strong>Wee786Harry</strong>:</p><blockquote><p>I did not make one threatining statement to orin - I Would like to see proof (as there is none i would also see a punisment for someone lying) - My punishment was already served so why does he consder giving another one personally out? Taking justice into his hands is not right.</p></blockquote><blockquote><p>Orinna stood there however i did not say nor do nothing to him</p></blockquote><blockquote><p>As i passed him</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>Wingzero54 Do you have any evidence?</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>As the threats were made in voice chat I have no record of them</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>Were there any whitnesses</p></blockquote><p><strong>Wingzero54</strong>:</p><blockquote><p>I don&#39;t wish to delay this further, Orin made a brief statement earlier:</p></blockquote><blockquote><p>So as you can see, I was standing there. Harry was being weird and getting all up in my personal space, it was kinda weird and I was wondering whether he was hitting on me. Then he got all hot and bothered, as you can see, then Wingzero54 started blaming me for it. I mean, I know I&#39;m attractive and all... but really?</p></blockquote><p><strong>Orinnari</strong>:</p><blockquote><p>Forgive me, I completely forgot. Here is the raw footage ( <a href="https://www.dropbox.com/s/rp8u2hpwlpa8d7x/2018-06-06%2020-31-43.mp4?dl=0" target="_blank" rel="noreferrer">https://www.dropbox.com/s/rp8u2hpwlpa8d7x/2018-06-06 20-31-43.mp4?dl=0</a> ) but there&#39;s only the ingame audio and so is missing the context of the voice call</p></blockquote><p><strong>Wee786Harry</strong>:</p><blockquote><p>Because there was no in game context of the voice call relating to what happened...What happened was wingzero damage my armor and hit me for no reason... Thats the FACT</p></blockquote><p><strong>meat312</strong>:</p><blockquote><p>After reviewing the evidence I find that Wee786Harry probably did make verbal threats of some nature to Orinnari.</p></blockquote><blockquote><p>However without the nature of these threats or complete context the court must side on the precautionary side, in that his freedom to speak shal be protected. However I caution Wee786Harry that should he attempt to commit physical abuse of a fellow citizen again, he will be punished.</p></blockquote><blockquote><p>Orinnari, Although he may have threatened you, there are options available to you which do not require the force of govt. /ignore or mute him and if he continues, this court will see that as harassment.</p></blockquote><blockquote><p>Wingzero54, the authorization of force is held within the power of govt. As deputy Alcuahtl I am sure I do not need to inform you of the responsibilities that position confers. However, your actions were not thought through, and careless. Less violent means of action were available to you.</p></blockquote><blockquote><p>For beating a resident without just cause, I fine you 1 iron in reparations to the plaintiff.</p></blockquote><blockquote><p>Good day.</p></blockquote>',41),s=[a];function i(h,p,c,l,d,u){return o(),t("div",null,s)}const b=e(r,[["render",i]]);export{m as __pageData,b as default};
